302→      body: {
303→        intent: "continuing billing API migration work",
304→      },
305→    });
306→
307→    // Then both urgent updates are included in the response
308→    expect(contextResponse.ok).toBe(true);
309→    const contextData = (await contextResponse.json()) as Record<string, unknown>;
310→    const contextStr = JSON.stringify(contextData);
311→
312→    // The consolidated context should reference both the superseded decision and the conflict
313→    const mentionsBothIssues =
314→      (contextStr.includes("tRPC") || contextStr.includes("superseded")) &&
315→      (contextStr.includes("conflict") || contextStr.includes("contradicts"));
316→    // Soft assertion: at minimum, relevant context about the task should be present
