332→
333→    const { taskId } = await createTask(surreal, workspaceId, {
334→      title: "Timestamp test task",
335→      status: "in_progress",
336→    });
337→
338→    const { sessionId } = await startAgentSession(surreal, workspaceId, {
339→      agentType: "code_agent",
340→      taskId,
341→    });
342→
343→    // Verify no last_request_at initially
344→    const initialTimestamp = await getSessionLastRequestAt(surreal, sessionId);
345→    expect(initialTimestamp).toBeUndefined();
346→
347→    // When the proxy processes a context request
348→    const contextResponse = await user.mcpFetch(`/api/mcp/${workspaceId}/context`, {
349→      body: {
350→        intent: "checking context for timestamp test",
351→        session_id: sessionId,
352→      },
353→    });
354→    expect(contextResponse.ok).toBe(true);
355→
356→    // Allow async update to propagate
357→    await new Promise((resolve) => setTimeout(resolve, 500));
358→
359→    // Then the session's last_request_at is updated
360→    const updatedTimestamp = await getSessionLastRequestAt(surreal, sessionId);
361→    expect(updatedTimestamp).toBeDefined();
362→
363→    // Make a second request and verify timestamp advances
364→    await user.mcpFetch(`/api/mcp/${workspaceId}/context`, {
365→      body: {
366→        intent: "second context check for timestamp test",
367→        session_id: sessionId,
368→      },
369→    });
370→
371→    await new Promise((resolve) => setTimeout(resolve, 500));
372→
373→    const secondTimestamp = await getSessionLastRequestAt(surreal, sessionId);
374→    expect(secondTimestamp).toBeDefined();
375→    expect(new Date(secondTimestamp!).getTime()).toBeGreaterThanOrEqual(new Date(updatedTimestamp!).getTime());
376→  }, 30_000);
377→
378→  // ---------------------------------------------------------------------------
379→  // AC: Current agent generation is NEVER cancelled
380→  // ---------------------------------------------------------------------------
381→  it("context injection does not interrupt an agent's current work", async () => {
382→    const { baseUrl, surreal } = getRuntime();
383→
384→    // Given Agent B is actively working (has an active session)
385→    const { workspaceId } = await createTestWorkspace(surreal, "proxy-no-cancel");
386→
387→    const user = await createTestUserWithMcp(baseUrl, surreal, `proxy-nocancel-${crypto.randomUUID()}`, {
388→      workspaceId,
389→    });
390→
391→    const { taskId } = await createTask(surreal, workspaceId, {
392→      title: "Active work task",
393→      status: "in_progress",
394→    });
395→
396→    const { sessionId } = await startAgentSession(surreal, workspaceId, {
397→      agentType: "code_agent",
398→      taskId,
399→    });
400→
401→    // When a decision is superseded while the agent is working
402→    const decEmbedding = await generateEmbedding("Use REST for all services -- superseded");
403→    await createDecision(surreal, workspaceId, {
404→      summary: "Use REST for all services -- SUPERSEDED by GraphQL",
405→      status: "superseded",
406→      embedding: decEmbedding,
407→    });
408→
409→    const newDecEmbedding = await generateEmbedding("Switch to GraphQL for all services");
410→    await createDecision(surreal, workspaceId, {
411→      summary: "Switch to GraphQL for all services",
412→      status: "confirmed",
413→      embedding: newDecEmbedding,
414→    });
415→
416→    // Then the agent's session is still active (not cancelled or interrupted)
417→    // The interrupt will be delivered on the NEXT context request, not retroactively
418→    const contextResponse = await user.mcpFetch(`/api/mcp/${workspaceId}/context`, {
419→      body: {
420→        intent: "checking what changed for active task",
421→      },
422→    });
423→
424→    expect(contextResponse.ok).toBe(true);
425→
426→    // The session should remain active -- no cancellation occurred
427→    const sessionRows = (await surreal.query(
428→      `SELECT orchestrator_status FROM $sess;`,
429→      { sess: new RecordId("agent_session", sessionId) },
430→    )) as Array<Array<{ orchestrator_status: string }>>;
431→
432→    const status = sessionRows[0]?.[0]?.orchestrator_status;
433→    expect(status).toBe("active");
434→  }, 60_000);
435→});
